# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

import tensorflow as tf
from flask import Flask, request, jsonify
import pandas as pd
import numpy as np
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
import os
import io
from PIL import Image
import base64
from werkzeug.utils import secure_filename
import uuid

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

# Create upload directory
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Global model and training parameters
model = None
label_encoder = LabelEncoder()
training_data = []

def create_model(num_classes, input_shape=(224, 224, 3)):
    """Create CNN model for image classification"""
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(64, activation='relu'),
        tf.keras.layers.Dropout(0.5),
        tf.keras.layers.Dense(num_classes, activation='softmax')
    ])
    return model

def preprocess_data(csv_path):
    """Load and preprocess CSV data"""
    df = pd.read_csv(csv_path)
    # Assume columns: 'image_path', 'label'
    return df

def load_and_preprocess_image(image_path):
    """Load and preprocess image for training"""
    img = Image.open(image_path)
    img = img.resize((224, 224))
    img_array = np.array(img)
    if len(img_array.shape) == 2:
        img_array = np.stack([img_array] * 3, axis=-1)
    img_array = img_array.astype('float32') / 255.0
    return img_array

def train_model():
    """Train the model with loaded data"""
    global model, training_data
    
    if len(training_data) < 2:
        return False
    
    # Prepare data
    images = []
    labels = []
    
    for data in training_data:
        try:
            img = load_and_preprocess_image(data['image_path'])
            images.append(img)
            labels.append(data['label'])
        except Exception as e:
            print(f"Error loading image {data['image_path']}: {e}")
            continue
    
    if len(images) < 2:
        return False
    
    X = np.array(images)
    y = np.array(labels)
    
    # Encode labels
    encoded_labels = label_encoder.fit_transform(y)
    num_classes = len(np.unique(encoded_labels))
    
    # Create and compile model
    model = create_model(num_classes)
    model.compile(optimizer='adam',
                  loss='sparse_categorical_crossentropy',
                  metrics=['accuracy'])
    
    # Train model
    X_train, X_test, y_train, y_test = train_test_split(
        X, encoded_labels, test_size=0.2, random_state=42
    )
    
    model.fit(X_train, y_train, 
              epochs=5, 
              validation_data=(X_test, y_test),
              batch_size=32)
    
    return True

def add_training_example(image_path, label):
    """Add new training example to dataset"""
    global training_data
    training_data.append({
        'image_path': image_path,
        'label': label
    })
    return True

@app.route('/upload', methods=['POST'])
def upload_file():
    """Upload CSV file for training"""
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file:
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        
        # Process CSV
        try:
            df = preprocess_data(filepath)
            for _, row in df.iterrows():
                add_training_example(row['image_path'], row['label'])
            
            # Retrain model
            success = train_model()
            return jsonify({
                'message': 'Training data uploaded successfully',
                'model_trained': success
            })
        except Exception as e:
            return jsonify({'error': str(e)}), 500

@app.route('/contribute', methods=['POST'])
def contribute_example():
    """Contribute new training example"""
    try:
        data = request.get_json()
        image_data = data.get('image_data')
        label = data.get('label')
        
        if not image_data or not label:
            return jsonify({'error': 'Missing image_data or label'}), 400
        
        # Decode base64 image
        image_bytes = base64.b64decode(image_data.split(',')[1])
        image_filename = f"{uuid.uuid4()}.jpg"
        image_path = os.path.join(app.config['UPLOAD_FOLDER'], image_filename)
        
        with open(image_path, 'wb') as f:
            f.write(image_bytes)
        
        # Add to training data
        add_training_example(image_path, label)
        
        # Retrain model
        success = train_model()
        
        return jsonify({
            'message': 'Training example contributed successfully',
            'model_updated': success
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    """Make prediction on new image"""
    global model
    if model is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    try:
        data = request.get_json()
        image_data = data.get('image_data')
        
        if not image_data:
            return jsonify({'error': 'Missing image_data'}), 400
        
        # Decode base64 image
        image_bytes = base64.b64decode(image_data.split(',')[1])
        image = Image.open(io.BytesIO(image_bytes))
        image = image.resize((224, 224))
        image_array = np.array(image)
        
        if len(image_array.shape) == 2:
            image_array = np.stack([image_array] * 3, axis=-1)
        
        image_array = image_array.astype('float32') / 255.0
        image_array = np.expand_dims(image_array, axis=0)
        
        # Make prediction
        predictions = model.predict(image_array)
        predicted_class = np.argmax(predictions[0])
        confidence = predictions[0][predicted_class]
        
        # Decode label
        predicted_label = label_encoder.inverse_transform([predicted_class])[0]
        
        return jsonify({
            'prediction': predicted_label,
            'confidence': float(confidence)
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)